import anthropic
from dataclasses import dataclass

client = anthropic.Anthropic()

@dataclass
class Plan:
    steps: list[str]
    score: float


def generate_plans(
    task: str, available_tools: list[str], n: int = 3
) -> list[Plan]:
    """Generate n candidate multi-step tool-call plans."""
    tools_str = ", ".join(available_tools)
    prompt = (
        f"Task: {task}\n"
        f"Available tools: {tools_str}\n\n"
        f"Write {n} distinct plans for completing this task. "
        "Each plan is a numbered list of tool-call steps. "
        "Separate plans with '---'."
    )
    resp = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=1024,
        messages=[{"role": "user", "content": prompt}],
    )
    raw_plans = resp.content[0].text.strip().split("---")
    plans = []
    for raw in raw_plans:
        steps = [
            line.lstrip("0123456789.) ").strip()
            for line in raw.strip().splitlines()
            if line.strip()
        ]
        if steps:
            plans.append(Plan(steps=steps, score=0.0))
    return plans[:n]


def score_plan(task: str, plan: Plan) -> float:
    """Have the model rate how likely this plan is to succeed."""
    steps_str = "\n".join(f"{i+1}. {s}" for i, s in enumerate(plan.steps))
    prompt = (
        f"Task: {task}\n"
        f"Proposed plan:\n{steps_str}\n\n"
        "Rate this plan's likelihood of success (0.0 to 1.0). "
        "Consider: completeness, efficiency, risk of failure. "
        "Reply with a single number."
    )
    resp = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=8,
        messages=[{"role": "user", "content": prompt}],
    )
    try:
        return float(resp.content[0].text.strip())
    except ValueError:
        return 0.5


def best_plan(task: str, available_tools: list[str]) -> Plan:
    """Generate candidate plans, score them, return the best."""
    plans = generate_plans(task, available_tools, n=3)
    for plan in plans:
        plan.score = score_plan(task, plan)
    return max(plans, key=lambda p: p.score)


# Example
plan = best_plan(
    task="Find the top 3 open GitHub issues in the anthropics/anthropic-sdk-python repo "
         "and summarise each in one sentence.",
    available_tools=["search_github_issues", "read_issue", "summarise_text"],
)
print(f"Best plan (score={plan.score:.2f}):")
for i, step in enumerate(plan.steps, 1):
    print(f"  {i}. {step}")
